public class Blablabla {  
     public static void main(String[] args) { 
           int i = 10; 
           while (i > 0) { 
                int j = 2 * i; 
                while (j > i) { 
                     j = j - 4; 
                     i = i - 1; 
                     System.out.println("blablabla"); 
                } 
           } 
     } 
}

